(function(){"use strict";window.Tasks={tasks:[],container:null,filters:{status:"all",priority:"all"},init:function(n,t=[]){(this.container=document.getElementById(n),this.container)&&(this.tasks=t,this.render(),this.attachEventListeners())},render:function(){const t=this.getFilteredTasks();let n='<ul class="task-list">';t.forEach(t=>{const i=t.completed?"checked":"",r=t.completed?"completed":"";n+=`
                    <li class="task-item ${r}" data-id="${t.id}">
                        <input type="checkbox" class="task-checkbox" ${i}>
                        <div class="task-content">
                            <p class="task-title">${this.escapeHtml(t.title)}</p>
                            <div class="task-meta">
                                <span class="priority-badge priority-${t.priority}">${t.priority}</span>
                                <span class="task-date">${t.dueDate||"Немає дати"}</span>
                            </div>
                        </div>
                        <div class="task-actions">
                            <button class="task-action-btn edit-btn" title="Редагувати">✏️</button>
                            <button class="task-action-btn delete-btn" title="Видалити">🗑️</button>
                        </div>
                    </li>
                `});n+="<\/ul>";this.container.innerHTML=n},attachEventListeners:function(){this.container.querySelectorAll(".task-checkbox").forEach(n=>{n.addEventListener("change",n=>{const t=n.target.closest(".task-item").dataset.id;this.toggleTask(t)})});this.container.querySelectorAll(".delete-btn").forEach(n=>{n.addEventListener("click",n=>{const t=n.target.closest(".task-item").dataset.id;confirmAction("Ви впевнені, що хочете видалити це завдання?")&&this.deleteTask(t)})});this.container.querySelectorAll(".edit-btn").forEach(n=>{n.addEventListener("click",n=>{const t=n.target.closest(".task-item").dataset.id;this.editTask(t)})})},toggleTask:function(n){const t=this.tasks.find(t=>t.id==n);t&&(t.completed=!t.completed,this.render(),this.attachEventListeners())},deleteTask:function(n){this.tasks=this.tasks.filter(t=>t.id!=n);this.render();this.attachEventListeners()},editTask:function(n){const t=this.tasks.find(t=>t.id==n);if(t){const n=new CustomEvent("taskEdit",{detail:t});this.container.dispatchEvent(n)}},setFilter:function(n,t){this.filters[n]=t;this.render();this.attachEventListeners()},getFilteredTasks:function(){return this.tasks.filter(n=>{const t=this.filters.status==="all"||(this.filters.status==="completed"?n.completed:!n.completed),i=this.filters.priority==="all"||n.priority===this.filters.priority;return t&&i})},escapeHtml:function(n){const t=document.createElement("div");return t.textContent=n,t.innerHTML}};console.log("StudentHelper tasks.js initialized")})();document.addEventListener("DOMContentLoaded",function(){const n=document.getElementById("descriptionInput"),t=document.getElementById("charCount");if(n&&t){function i(){t.textContent=n.value.length}i();n.addEventListener("input",i)}});document.addEventListener("DOMContentLoaded",function(){const n=document.getElementById("descriptionInput"),t=document.getElementById("charCount");if(n&&t){function i(){const i=n.value.length;t.textContent=i+" / 500 символів"}i();n.addEventListener("input",i)}});document.addEventListener("DOMContentLoaded",function(){let t=null;const n=document.getElementById("searchInput");if(n){const i=sessionStorage.getItem("taskSearchCursorPosition"),r=sessionStorage.getItem("taskSearchFocus");if(r==="true"){if(n.focus(),i!==null){const t=parseInt(i,10);n.setSelectionRange(t,t)}sessionStorage.removeItem("taskSearchFocus");sessionStorage.removeItem("taskSearchCursorPosition")}n.addEventListener("keyup",function(){clearTimeout(t);sessionStorage.setItem("taskSearchFocus","true");sessionStorage.setItem("taskSearchCursorPosition",this.selectionStart);t=setTimeout(function(){},300)})}});